UIImage * _Nullable VCBrandIconImage(void) {
    static UIImage *image = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        NSData *data = [[NSData alloc] initWithBase64EncodedString:VCBrandIconBase64() options:0];
        if (data.length > 0) {
            image = [UIImage imageWithData:data];
        }
    });
    return image;
}
